/* ══ PARTÍCULAS ══ */
const emojis=['🌹','💕','✨','🌸','💫','❣️','🌺','💝'];
const pWrap=document.getElementById('particles');
for(let i=0;i<20;i++){
  const p=document.createElement('div');
  p.className='particle';
  p.textContent=emojis[i%emojis.length];
  p.style.setProperty('--dur',(5+Math.random()*8)+'s');
  p.style.setProperty('--delay',(Math.random()*10)+'s');
  p.style.left=Math.random()*100+'vw';
  p.style.bottom='-30px';
  pWrap.appendChild(p);
}

/* ══ CONTRASEÑA ══ */
const VALID=['amor','cariño','carino','un abrazo','abrazo','tiempo','tu amor','mi amor'];
const ERRORS=[
  "Casi... pero esa no es la llave de mi corazón. 🗝️",
  "Mmm, intenta de nuevo. Me gusta cuando te esfuerzas por entrar aquí. 😏",
  "Eso no es... pero me encanta que estés intentando descubrir mis secretos. 🌹"
];
let attempts=0;
document.getElementById('password-input').addEventListener('keydown',e=>{ if(e.key==='Enter') checkPassword(); });

function checkPassword(){
  const input=document.getElementById('password-input');
  const val=input.value.trim().toLowerCase();
  if(!val) return;
  if(VALID.includes(val)){
    if(window._tryPlay) window._tryPlay();
    enterHeart();
  } else {
    const errEl=document.getElementById('error-msg');
    input.classList.remove('shake'); void input.offsetWidth; input.classList.add('shake');
    errEl.textContent=ERRORS[Math.min(attempts,ERRORS.length-1)];
    errEl.classList.add('show');
    const dots=document.querySelectorAll('#dots .dot');
    if(attempts<dots.length) dots[attempts].classList.add('used');
    attempts++; input.value='';
    setTimeout(()=>input.classList.remove('shake'),500);
  }
}

function enterHeart(){
  const ts=document.getElementById('transition-screen');
  const ls=document.getElementById('lock-screen');
  ts.classList.add('active');
  setTimeout(()=>{ ls.style.display='none'; setTimeout(()=>{ ts.classList.remove('active'); showHeart(); },600); },2200);
}

function showHeart(){
  const hs=document.getElementById('heart-screen');
  hs.style.display='flex'; hs.style.animation='fadeIn 1s ease';
  setTimeout(()=>{ document.getElementById('heart-caption').classList.add('visible'); },500);
  setTimeout(()=>{ drawHeart(); },1000);
  setTimeout(()=>{ document.getElementById('final-msg').classList.add('visible'); },7000);
}

/* ══ CORAZÓN DENSO: izquierda=Jhannara, derecha=Joseph ══ */
function drawHeart(){
  const canvas=document.getElementById('heart-canvas');
  const SIZE=Math.min(window.innerWidth-16, 520);
  canvas.width=SIZE; canvas.height=SIZE;
  canvas.style.width=SIZE+'px'; canvas.style.height=SIZE+'px';

  const ctx=canvas.getContext('2d');
  const cx=SIZE/2, cy=SIZE*0.47, sc=SIZE*0.29;
  const FS=Math.max(9,Math.round(SIZE/46));

  ctx.textBaseline='middle';

  const charW=FS*0.62;
  const wordMaxW=8*charW+charW;
  const stepX=wordMaxW;
  const stepY=FS*1.65;

  const CL=['#c0394b','#c73d50','#cf4256','#d8526a','#e06378'];
  const CR=['#e8758a','#e07888','#d47a78','#c98068','#c9955c'];

  const rows=[];
  for(let py=stepY*0.4; py<SIZE-stepY*0.3; py+=stepY){
    const rw=[];
    const off=(Math.floor(py/stepY)%2===0)?0:stepX*0.5;
    for(let px=-off; px<SIZE+stepX; px+=stepX){
      const mx=px+stepX/2, my=py;
      const x=(mx-cx)/sc, y=-(my-cy)/sc;
      if(Math.pow(x*x+y*y-1,3)-x*x*y*y*y<=0.04){
        rw.push({x:px,y:py,left:mx<=cx});
      }
    }
    if(rw.length) rows.push(rw);
  }

  const total=rows.length;
  rows.forEach((row,ri)=>{
    setTimeout(()=>{
      const ci=Math.floor((ri/total)*(CL.length-1));
      row.forEach(w=>{
        ctx.font='bold '+FS+'px Arial,sans-serif';
        ctx.fillStyle=w.left?CL[ci]:CR[ci];
        ctx.globalAlpha=0.92;
        ctx.fillText(w.left?'Jhannara':'Joseph',w.x,w.y);
      });
    },ri*50);
  });
}
